const std = @import("std");

pub fn main() void {
    const v = parseConfig() catch unreachable;
    std.log.info("loaded {s}", .{v});
}

pub fn first(slice: []const u8) u8 {
    return slice[0] catch |_| unreachable;
}

pub fn main() !void {
